mapper.update:
/* com.erns.es.login.mapper.LoginDAO.updatePswdErrorCnt */
UPDATE T_MEMB_INF SET
	  PSWD_ERR_CNT   = PSWD_ERR_CNT +1

	AND MEMB_SEQ = #{seq, jdbcType=INTEGER}

/* com.erns.es.login.mapper.LoginDAO.updateResetPswdErrorCnt */
UPDATE T_MEMB_INF SET
	  PSWD_ERR_CNT   = 0

	AND MEMB_SEQ = #{seq, jdbcType=INTEGER}

/* com.erns.es.login.mapper.LoginDAO.updateLoingInfo */
UPDATE T_MEMB_INF SET
	  RCT_ACS_DTTM = now()
	, RCT_ACS_IP = #{lastAccessIp, jdbcType=VARCHAR}

	AND MEMB_SEQ = #{seq, jdbcType=INTEGER}

mapper.select:
/* com.erns.es.login.mapper.LoginDAO.loadUser */ SELECT AA.MEMB_SEQ AS SEQ , AA.MEMB_ID AS USER_ID , AA.MEMB_NAME AS USER_NAME , AA.PSWD AS PASSWORD , AA.PHONE AS PHONE , AA.EMAIL AS EMAIL
, AA.USE_YN AS USE_YN , AA.PSWD_CHNG_DTTM AS PSWD_CHNG_DATE , AA.PSWD_ERR_CNT AS PSWD_ERR_CNT , AA.PSWD_INIT_YN AS PSWD_INIT_YN
FROM T_MEMB_INF AA
AND AA.MEMB_ID = #{value, jdbcType=VARCHAR}
